"""
MKT Christ Commentary — Joshua chapters 9–11
Run: python3 scripts/zc-christ-joshua-9-11.py

Key Christological decisions:
- Ch9: Gibeonite deception read as Gentile seeking covenant by hearing (Rom 10:17)
- Ch9 v15: The irrevocable oath as type of Christ as covenant surety (Heb 7:22)
- Ch9 v23-27: Curse-to-service transformation anticipates how curse becomes priestly calling
- Ch10 v24: Foot on necks = Ps 110:1; Christ's enemies as footstool (Heb 10:13)
- Ch10 v26-27: Hanging kings on trees = Gal 3:13/Deut 21:22-23; Christ becomes a curse
- Ch11 v15: Moses→Joshua obedience chain = Christ fulfills all righteousness (Matt 5:17)
- Ch11 v20: Hardened hearts = John 12:40 pattern; divine sovereignty in judgment
- Ch11 v21-22: Anakim destroyed, survivors in Gath = David-Goliath type of Christ
- Ch11 v23: Rest from war = Heb 4:8-9; the greater rest Christ provides
"""

import json, pathlib

ROOT = pathlib.Path('/home/domad/Documents/bible-study-website')

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOSHUA = {
  "9": {
    "1": '<p>A theme: the coalition of western kings gathering against Israel mirrors the Psalm 2 pattern — "Why do the nations conspire and the peoples plot in vain? The kings of the earth set themselves, and the rulers take counsel together, against the LORD and against his Anointed" (Ps 2:1-2). The nations\' resistance to YHWH\'s purposes recurs throughout Scripture and reaches its climax in the crucifixion (Acts 4:25-27 applies Ps 2 directly to the coalition against Jesus).</p>',
    "2": '<p>A theme: the unity of the opposing nations ("one purpose") against YHWH\'s purposes anticipates the unified opposition to Christ. Yet every gathering of powers against YHWH\'s anointed in Scripture results in their defeat — the pattern of Ps 2 ends not with the nations\' triumph but with the Son\'s installation as king (Ps 2:6-9).</p>',
    "3": '<p>A theme: while the nations gather to fight, the Gibeonites respond differently — they hear and act on what they hear. This contrast between those who fight against YHWH\'s purposes and those who seek inclusion in them anticipates the great division in response to the gospel: some harden their hearts, some seek shelter (cf. Matt 11:12; John 1:11-12).</p>',
    "4": '<p>A theme: the Gibeonites\' cunning disguise — worn sacks, old wineskins — is a desperate act of faith in a paradoxical sense: they believe YHWH\'s power is real (v9) and that their only hope is to find a place within his covenant. The "foolishness" of their approach echoes the paradox that God\'s purposes are often advanced through what appears weak or indirect (1 Cor 1:25).</p>',
    "5": '<p>A theme: the physical markers of a long journey — patched sandals, worn-out clothes, dry bread — are the Gibeonites\' only credentials for covenant inclusion. They come with nothing but evidence of the journey itself. This anticipates the condition of the Gentile nations who come to Christ with nothing but their need: "Come to me, all who are weary and burdened, and I will give you rest" (Matt 11:28).</p>',
    "6": '<p>A type: the Gibeonites approach Joshua (whose name is the Hebrew form of "Jesus") at Gilgal — the covenant-renewal site — and ask to be included in a covenant of life. "Make a treaty with us" is the Gentile nations\' petition at the feet of Israel\'s leader-savior. Every person who comes to Christ for life participates in this pattern: approaching the one who holds the covenant of life and asking to be included.</p>',
    "7": '<p>A theme: "What if you live near us? How could we make a treaty with you?" The Israelites\' hesitation reflects a concern about covenant boundaries. Christ removes such boundaries: the dividing wall of hostility has been abolished (Eph 2:14), and those who were "far off" have been brought near through his blood (Eph 2:13).</p>',
    "8": '<p>A revelation of God: "We are your servants" — the Gibeonites\' self-presentation as servants echoes the position of those who come to Christ. Paradoxically, those who surrender to Christ as Lord discover that this servanthood is freedom: "you are no longer a slave, but a son" (Gal 4:7). The surrender that looks like loss is the path to inclusion in the covenant family.</p>',
    "9": '<p>A theme: "Your servants have come... because of the reputation of the LORD your God. We heard the report about him." Faith comes by hearing (Rom 10:17). The Gibeonites\' case for inclusion is entirely based on what they heard about YHWH — the same basis on which the nations are called to faith in the gospel. The "report" (<em>šēmaʿ</em>) that saves them corresponds to the <em>ĕmûnāh</em>-response to the <em>šēmaʿ</em> (the thing heard) in Rom 10:17.</p>',
    "10": '<p>A theme: the Gibeonites\' specific reference to Sihon and Og — the Transjordanian kings defeated in Moses\'s time — shows that the reputation of YHWH had already spread beyond Israel. This prefigures Paul\'s argument in Rom 1:20 that God\'s power is universally known, and that the nations are without excuse — but also Rom 10:18: "their voice has gone out to all the earth."</p>',
    "11": '<p>A theme: "Our elders and all who live in our country said to us..." — the transmission of testimony about YHWH\'s acts through community leaders mirrors the role of the church in preserving and transmitting the gospel. Covenant knowledge is not merely individual; it is communally mediated and authorized.</p>',
    "12": '<p>A theme: bread from the oven — fresh bread as a sign of proximity. The Gibeonites\' dry, crumbled bread proves (deceptively) their distance. The "bread of life" that Christ offers is fresh and sustaining: "I am the bread of life; whoever comes to me shall not hunger" (John 6:35). The contrast is between the bread that becomes stale and the living bread that never runs out.</p>',
    "13": '<p>A theme: the evidence of the journey — worn-out, cracked, patched — describes those who come to Christ in need. The weary and burdened (Matt 11:28) come as they are, worn down by the journey. Christ receives them not in their strength but in their need.</p>',
    "14": '<p>A revelation of God: Israel "did not consult the LORD" — the failure that leads to an unintended covenant. Contrast with Christ, who in every critical moment sought the Father\'s will: "the Son can do nothing by himself; he can only do what he sees his Father doing" (John 5:19). The recurring human failure to seek divine guidance contrasts with Christ\'s perfect filial attentiveness.</p>',
    "15": '<p>A type: the sworn oath by which Joshua bound Israel to protect the Gibeonites — irrevocable even though made under deception — foreshadows Christ as the "guarantor of a better covenant" (Heb 7:22). Once the covenant oath is sworn, it binds regardless of the circumstances. Christ\'s covenant with his people, sealed in his blood, is similarly irrevocable: "he holds his priesthood permanently" and "is able to save completely those who come to God through him" (Heb 7:24-25).</p>',
    "16": '<p>A theme: the three-day interval before the deception is revealed echoes the three-day pattern throughout Scripture — a period of hiddenness followed by revelation. The third day is consistently associated with divine reversal and covenant vindication in the biblical narrative, culminating in Christ\'s resurrection on the third day (1 Cor 15:4).</p>',
    "17": '<p>A theme: the four Gibeonite towns — Gibeon, Chephirah, Beeroth, Kiriath-jearim — are preserved because of the sworn covenant. The "cities of the outsiders" that are included in the covenant people anticipate the Gentile communities that become part of the church through the covenant in Christ\'s blood. Kiriath-jearim later houses the ark (1 Sam 7:1-2) — the covenant presence dwells among the former outsiders.</p>',
    "18": '<p>A theme: "The assembly grumbled against the leaders" — the same grumbling pattern as the wilderness generation. The leaders maintain the covenant obligation despite popular pressure. Christ similarly maintains his covenant faithfulness under pressure from all sides: from the crowd, the religious establishment, and his own disciples (John 6:60-69).</p>',
    "19": '<p>A theme: "We have given them our oath in the name of the LORD, and we cannot harm them." The inviolability of the oath "in the name of the LORD" anticipates the absolute security of those who are in Christ. YHWH himself cannot — would not — break his own sworn oath. This is the ground of assurance in Heb 6:17-18: "Because God wanted to make the unchanging nature of his purpose very clear to the heirs of what was promised, he confirmed it with an oath."</p>',
    "20": '<p>A revelation of God: "We will let them live, so that God\'s anger does not fall on us because of the oath we gave them." The wrath that would follow covenant violation is averted by covenant faithfulness. In Christ, the wrath that would fall on his people for their covenant violations is borne by him: "God presented Christ as a sacrifice of atonement" (Rom 3:25). The logic is parallel — covenant integrity averts wrath.</p>',
    "21": '<p>A theme: woodcutters and water-carriers "for the community" — the Gibeonites\' servile role in supporting the covenant community. In the new covenant, all believers are called to serve: "each one should use whatever gift he has received to serve others" (1 Pet 4:10). The Gibeonite pattern of outsiders finding inclusion through service in the covenant community anticipates the multi-ethnic, multi-national body of Christ.</p>',
    "22": '<p>A revelation of God: Joshua confronts the deception honestly rather than pretending it did not happen. Christ similarly confronts sin with honesty — he names what is wrong — while maintaining the relationship. "He came to what was his own, and his own people did not receive him" (John 1:11) — the deception and rejection are real, but the covenant purpose is not defeated by them.</p>',
    "23": '<p>A type: "Cursed: you will never cease to be slaves — woodcutters and water-carriers — for the house of my God." The curse is transformed into perpetual temple service. This anticipates how Christ transforms the curse — "cursed is everyone who does not continue in all things written in the Book of the Law to do them" (Gal 3:10) — into priestly access: "he has made us to be a kingdom and priests to serve his God and Father" (Rev 1:6). The Gibeonites\' curse-transformed-to-service is a shadow of this greater transformation.</p>',
    "24": '<p>A theme: "We feared for our lives because of you — that is why we did this." The Gibeonites\' fear drove them to seek any available means of inclusion in the covenant. This "fear that drives to Christ" is the beginning of wisdom (Prov 9:10). The terror of YHWH\'s judgment was precisely what motivated the nations to seek his protection, just as awareness of God\'s holiness and human sin drives people to seek refuge in Christ.</p>',
    "25": '<p>A revelation of God: "In your hands. Do to us whatever you think is good and right." Complete surrender to the covenant lord\'s mercy — no negotiation, no conditions. This is the posture of faith: "I am crucified with Christ; it is no longer I who live" (Gal 2:20). The Gibeonites model total surrender to the one in whose hands they have placed themselves.</p>',
    "26": '<p>A type: Joshua protects the Gibeonites from those who would destroy them, interceding between the community\'s anger and the covenant people. This is a type of Christ\'s intercession: "He always lives to intercede for them" (Heb 7:25). The high priest who stands between the wrath of the community and those who have found covenant shelter is a figure of Christ\'s mediatorial role.</p>',
    "27": '<p>A shadow: the Gibeonites are assigned to serve at the altar "at whatever place the LORD would choose" — the deuteronomic formula pointing toward Jerusalem and ultimately toward Christ as the true temple. The outsiders who sought covenant life find their permanent service at the very place where YHWH makes his name to dwell (Deut 12:5). In the new covenant, "the place" is not Jerusalem but Christ himself (John 4:21-24), and all who are in him serve as a "holy priesthood" (1 Pet 2:5).</p>'
  },
  "10": {
    "1": '<p>A theme: Adonizedek ("my lord is righteousness") fears the spread of YHWH\'s kingdom and gathers opposition. The principalities and powers recognize the advance of God\'s reign and mount resistance — this pattern culminates in the cross, where the "ruler of this world" mobilized all opposition against Christ (John 12:31; 1 Cor 2:8: "none of the rulers of this age understood it, for if they had, they would not have crucified the Lord of glory").</p>',
    "2": '<p>A theme: Gibeon\'s defection alarms the coalition — one city switching allegiance to YHWH\'s cause weakens the whole system of opposition. In the same way, every individual who comes to Christ is a defection from the kingdom of darkness and an alarm to the powers that oppose God\'s purposes (Col 1:13: "he has rescued us from the dominion of darkness and brought us into the kingdom of the Son he loves").</p>',
    "3": '<p>A theme: Adonizedek rallies four kings to mount a punitive expedition against Gibeon. The enemy\'s response to covenant conversion is always violence or pressure to return — those who come to Christ face opposition precisely because their conversion is a threat to the kingdom of darkness. The five Amorite kings represent organized, systemic opposition to YHWH\'s covenant purposes.</p>',
    "4": '<p>A theme: "It has made peace with Joshua and the Israelites" — Gibeon\'s peace treaty with Israel is the reason for the attack. The peace that Christ brings — "peace with God through our Lord Jesus Christ" (Rom 5:1) — similarly provokes opposition from those who benefit from enmity. Christ said "I did not come to bring peace, but a sword" (Matt 10:34) — not because peace is not his goal but because the arrival of true peace disrupts false peace.</p>',
    "5": '<p>A theme: the five Amorite kings besiege Gibeon — those who sought covenant life are immediately threatened. The new believer who transfers allegiance to Christ faces exactly this: "In fact, everyone who wants to live a godly life in Christ Jesus will be persecuted" (2 Tim 3:12). The siege of Gibeon is the universal pattern of the world\'s response to covenant conversion.</p>',
    "6": '<p>A type: "Do not abandon your servants! Come up to us quickly — rescue us and help us!" The Gibeonites\' cry to their covenant lord is the prayer of the church under pressure. Christ is the suzerain who answers the vassal\'s cry: "I will not leave you as orphans; I will come to you" (John 14:18). The cry for help from those who have found covenant shelter is always answered by the covenant lord.</p>',
    "7": '<p>A revelation of God: Joshua responds immediately — "marched up from Gilgal with his entire fighting force, including all his best warriors." YHWH\'s response to his people\'s need is total: "If God is for us, who can be against us?... He who did not spare his own Son, but gave him up for us all — how will he not also, along with him, graciously give us all things?" (Rom 8:31-32). The divine warrior commits everything to the rescue of his covenant people.</p>',
    "8": '<p>A direct revelation: "Do not be afraid of them; I have given them into your hand." The pre-battle divine guarantee recurs throughout Joshua\'s campaign — the certainty of victory precedes the battle. Christ\'s resurrection was this same pre-battle guarantee: God "raised him from the dead and seated him at his right hand" (Eph 1:20), guaranteeing the final victory over every power before the battle is finished in history.</p>',
    "9": '<p>A theme: the overnight forced march — all-out effort, no holding back — to rescue the covenant people under siege. Christ\'s mission from the Father was similarly single-minded and total: "I have come down from heaven not to do my will but to do the will of him who sent me" (John 6:38). The complete commitment of the suzerain to rescue his vassal is a figure of Christ\'s incarnation as total commitment to his people\'s redemption.</p>',
    "10": '<p>A revelation of God: YHWH "threw them into panic" before Israel struck a blow — the divine action precedes and enables the human. In the spiritual battle, the victory over sin and death was accomplished by YHWH\'s action in raising Christ (Col 2:12-13), not by human spiritual effort. The panic that disintegrates the enemy\'s formation is the work of God, not human strategy.</p>',
    "11": '<p>A revelation of God: "More of them were killed by the hailstones than by the Israelites\' swords." The divine contribution to victory exceeds the human. Paul\'s warfare language emphasizes the same asymmetry: "the weapons we fight with are not the weapons of the world. On the contrary, they have divine power to demolish strongholds" (2 Cor 10:4). YHWH himself is the primary warrior; his people are instruments.</p>',
    "12": '<p>A revelation of God: Joshua commands the sun and moon, and they obey — creation at the service of redemption. Christ demonstrates this same authority over creation: "he got up and rebuked the winds and the waves, and it was completely calm" (Matt 8:26). The natural order responds to the commands of YHWH\'s servant because all creation was made through and for Christ (Col 1:16).</p>',
    "13": '<p>A shadow: the Book of Jashar preserved the account of YHWH\'s unprecedented intervention. The preservation of testimony to YHWH\'s acts of salvation — in written form, in the covenant community — points toward the Scripture\'s own role as preserved testimony. "These things are written that you may believe that Jesus is the Messiah, the Son of God, and that by believing you may have life in his name" (John 20:31).</p>',
    "14": '<p>A revelation of God: "There has never been a day like it — a day when the LORD listened to a human voice." The incarnation is the ultimate "day when YHWH listens to a human voice" — the Son of God prays as a human being, and the Father responds. At Gethsemane, Calvary, and the resurrection, the dialogue between the divine and human is at its most intense. Christ\'s cry from the cross ("My God, my God, why have you forsaken me?") and his resurrection vindication are the definitive divine-human encounter that the long day anticipates.</p>',
    "15": '<p>A theme: the return to Gilgal — the covenant renewal site — after the battle. The recurring return to the place of covenant commitment frames the campaign. In the Christian life, every battle is fought from the place of covenant assurance — baptism, the Lord\'s Table, the word of God — and returns to it. The covenant center is both the launch point and the resting point.</p>',
    "16": '<p>A theme: the five kings flee and hide in a cave — the powers of darkness retreating from YHWH\'s advancing kingdom. "The one who is in you is greater than the one who is in the world" (1 John 4:4). The hiding of defeated kings in a cave anticipates the final defeat of every power: "they called to the mountains and the rocks, \'Fall on us and hide us from the face of him who sits on the throne\'" (Rev 6:16).</p>',
    "17": '<p>A theme: the kings are found hiding — nothing is hidden from YHWH. "Nothing in all creation is hidden from God\'s sight. Everything is uncovered and laid bare before the eyes of him to whom we must give account" (Heb 4:13). The defeated powers cannot escape the final reckoning.</p>',
    "18": '<p>A theme: "Roll large stones to the entrance of the cave and post guards" — contain and proceed. The stone blocking the cave entrance is an ironic foreshadowing: a stone sealed an enemy\'s tomb at Joshua\'s command (v27), as a stone was sealed over Christ\'s tomb — only for Christ to emerge from his in resurrection, reversing the pattern (Matt 27:66; 28:2).</p>',
    "19": '<p>A revelation of God: "Don\'t you stay there! Pursue your enemies; cut off their retreat." The divine warrior strategy is relentless pursuit — no half-measures. This reflects the thoroughness of Christ\'s salvation: he "appeared once for all at the culmination of the ages to do away with sin by the sacrifice of himself" (Heb 9:26). The pursuit is total; the victory is meant to be complete.</p>',
    "20": '<p>A theme: "The survivors having taken refuge in the fortified cities" — even after a devastating defeat, some resistance persists. The Christian life is honest about the ongoing presence of sin and opposition after the decisive victory of the cross: "although the body is dead because of sin, the Spirit gives life" (Rom 8:10). The final mopping-up of remaining enemies is the work of the age between Christ\'s first and second coming.</p>',
    "21": '<p>A revelation of God: "No one dared to say a word against the Israelites" — the complete psychological and political collapse of opposition after YHWH\'s intervention. "At the name of Jesus every knee should bow, in heaven and on earth and under the earth" (Phil 2:10). The intimidated silence of all opposition before YHWH\'s advancing kingdom anticipates the universal acknowledgment of Christ\'s lordship.</p>',
    "22": '<p>A theme: the kings are brought out of the cave — exposed, brought to light. "He who does evil hates the light and will not come into the light for fear that his deeds will be exposed" (John 3:20). The exposure of the hidden powers is part of Christ\'s work: "he made a public spectacle of them, triumphing over them by the cross" (Col 2:15).</p>',
    "23": '<p>A revelation of God: the five kings represent the major power centers of the Canaanite world — Jerusalem, Hebron, Jarmuth, Lachish, Eglon. Their public defeat and execution signals the end of the old order. Christ\'s death and resurrection similarly defeat the "ruler of this world" (John 12:31) — not merely individuals but the systemic powers of sin, death, and the accuser.</p>',
    "24": '<p>A direct fulfillment (forward): "Put your feet on the necks of these kings." This enacts Ps 110:1: "Sit at my right hand until I make your enemies a footstool for your feet." The military ritual of foot-on-neck is the human enactment of a divine promise that the NT applies directly to Christ (Matt 22:44; Acts 2:35; Heb 1:13, 10:13). "He must reign until he has put all his enemies under his feet" (1 Cor 15:25).</p>',
    "25": '<p>A direct revelation: "Do not be afraid or discouraged. Be strong and courageous, for this is how the LORD will deal with all the enemies you fight." Joshua\'s commissioning words to his commanders mirror Christ\'s Great Commission: "All authority in heaven and on earth has been given to me... And surely I am with you always, to the very end of the age" (Matt 28:18-20). The assurance that YHWH\'s pattern of victory extends to all future battles is the same assurance Christ gives the church.</p>',
    "26": '<p>A type with direct NT fulfillment: the kings are executed and hung on five trees. This is the explicit type that Gal 3:13 fulfills: "Christ redeemed us from the curse of the law by becoming a curse for us — for it is written: \'Cursed is everyone who is hanged on a tree\'" (Deut 21:22-23). Joshua\'s hanging of defeated enemy kings anticipates the one who became a curse in the place of his enemies, bearing on the cross what his people deserved.</p>',
    "27": '<p>A type: the bodies taken down from the trees at sunset, buried in the same cave — the cave of defeat becomes a tomb. Christ\'s body was taken down from the cross before the Sabbath (John 19:31), fulfilling the Deut 21:23 requirement exactly. But where the Canaanite kings remain in their cave forever, Christ emerges from his tomb on the third day. The pattern of burial in the place of defeat is transformed by resurrection.</p>',
    "28": '<p>A theme: the systematic conquest formula — "struck with the sword... completely destroyed... treated as he had treated Jericho" — describes the comprehensive elimination of each center of resistance. Paul describes this kind of systematic spiritual conquest: "we take captive every thought to make it obedient to Christ" (2 Cor 10:5). The thoroughness of the campaign is the model for Christ\'s claim on every domain of existence.</p>',
    "29": '<p>A theme: Libnah — the campaign moves west, expanding the territory of YHWH\'s rule. The gospel\'s geographical spread — "Jerusalem, Judea, Samaria, and to the ends of the earth" (Acts 1:8) — follows this pattern of systematic expansion from a center outward.</p>',
    "30": '<p>A revelation of God: "The LORD also handed Libnah and its king over to Israel" — YHWH as the subject of every conquest. The recurring naming of YHWH as the one who "hands over" the enemy emphasizes divine agency in every advance of the kingdom. Every advance of the gospel is likewise YHWH\'s work: "The Lord added to their number daily those who were being saved" (Acts 2:47).</p>',
    "31": '<p>A revelation of God: Lachish falls in two days. YHWH\'s timing is precise — not one day less, not one day more. God\'s sovereignty over the timing of every event in his redemptive plan is reflected throughout: "when the fullness of time had come, God sent his Son" (Gal 4:4). The two-day detail signals providential precision, not chance.</p>',
    "32": '<p>A theme: the second day capture of Lachish. The recurring "second day" and "third day" details in the conquest narrative embed the temporal patterns that reach their fulfillment in Christ\'s death, burial, and third-day resurrection — the definitive "second/third day" event.</p>',
    "33": '<p>A theme: Gezer attempts to help Lachish — the worldly system of mutual reinforcement among opposed powers. Christ defeats not just individual sins but the entire system: "having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross" (Col 2:15). The systematic defeat of the coalition\'s support structures corresponds to Christ\'s defeat of the principalities.</p>',
    "34": '<p>A theme: the Eglon siege — the surrounding of the city that cuts off retreat. Paul describes the comprehensive scope of Christ\'s work in similar terms: "so that through the church, the manifold wisdom of God should be made known to the rulers and authorities in the heavenly realms" (Eph 3:10). The church is the advancing siege around the remaining strongholds of darkness.</p>',
    "35": '<p>A theme: "That same day" captures — the speed of divine action when the time is right. "See, now is the acceptable time; see, now is the day of salvation" (2 Cor 6:2). God\'s decisive acts in history come when they come, not according to human scheduling.</p>',
    "36": '<p>A revelation of God: Hebron — the city of the giants, the place where the spies despaired — falls to YHWH\'s army under Joshua. What the previous generation feared most becomes the theater of God\'s greatest victory. Christ engages and defeats what is most feared — death itself, "the last enemy" (1 Cor 15:26) — precisely where defeat seemed most certain.</p>',
    "37": '<p>A theme: the destruction of Hebron and its surrounding towns. The comprehensive scope of the victory — city and dependent towns — reflects the comprehensive scope of Christ\'s salvation: "the earth is the LORD\'s, and everything in it" (Ps 24:1). Nothing in the domain of sin and death is exempt from Christ\'s reclaiming work.</p>',
    "38": '<p>A theme: Debir ("the Word") captured. The city named for the inner sanctuary and divine speech falls to Joshua. In Christ, all that was hidden in the inner sanctuary — "the mystery hidden for ages" (Col 1:26) — is now made known. The Word of God who was hidden is now revealed in the incarnation.</p>',
    "39": '<p>A theme: the compliance formula — "as he had treated Hebron and Libnah" — establishes consistency of principle across every conquest. Christ\'s salvation is consistent across every person: "there is no difference between Jew and Gentile — the same Lord is Lord of all and richly blesses all who call on him" (Rom 10:12). The same Lord applies the same terms to every territory claimed.</p>',
    "40": '<p>A revelation of God: "He left no survivors; he devoted all who breathed to destruction, as the LORD God of Israel had commanded." The totality of the ḥērem points toward the final judgment — the complete elimination of everything that opposes YHWH\'s reign. "Nothing impure will ever enter it [the new Jerusalem]" (Rev 21:27). The conquest\'s totality is an enacted prophecy of the new creation\'s purity.</p>',
    "41": '<p>A theme: the geographic summary — from Kadesh-barnea to Gaza, from Goshen to Gibeon — marks the extent of the southern campaign. Christ\'s commission reaches the uttermost parts of the earth (Acts 1:8). The geographic comprehensiveness of Joshua\'s southern campaign is a type of the gospel\'s universal reach.</p>',
    "42": '<p>A direct revelation: "Joshua captured all these kings and their lands in one campaign, because the LORD, the God of Israel, fought for Israel." "In one campaign" points toward the cross as the one decisive act that accomplishes what no extended campaign could: "he has appeared once for all at the culmination of the ages to do away with sin by the sacrifice of himself" (Heb 9:26). A single event, a single sacrifice, a single campaign — sufficient for all.</p>',
    "43": '<p>A theme: the return to Gilgal — the covenant center — after every campaign phase. The church returns again and again to the covenant center — the word, the sacraments, the assembly — as the anchor of every advance and the resting place after every battle.</p>'
  },
  "11": {
    "1": '<p>A theme: Jabin of Hazor — the dominant northern power — gathers all regional kings against Israel. The final and largest coalition represents the maximum concentration of opposition to YHWH\'s purposes. This final gathering of all opposing power before Christ\'s decisive victory anticipates Rev 19:19: "the beast and the kings of the earth and their armies gathered together to wage war against the rider on the horse and his army."</p>',
    "2": '<p>A theme: the geographic comprehensiveness of the northern coalition — hill country, Arabah, foothills, heights — signals that all regions are represented. No territory is exempt from YHWH\'s claim: "the earth is the LORD\'s" (Ps 24:1). The coalition\'s attempt to hold all regions against YHWH fails — as every attempt to contain Christ\'s kingdom within limited geography ultimately fails.</p>',
    "3": '<p>A theme: the full ethnic catalogue — Canaanites, Amorites, Hittites, Perizzites, Jebusites, Hivites — gathers under the ḥērem. In the NT, this ethnic diversity appears differently: "there is neither Jew nor Gentile, neither slave nor free, nor is there male and female, for you are all one in Christ Jesus" (Gal 3:28). Where the old order gathered diverse nations under judgment, the new covenant gathers diverse nations under grace.</p>',
    "4": '<p>A theme: "As numerous as the sand on the seashore with a great many horses and chariots" — the formula for overwhelming force applied to Israel\'s enemies. This same formula (Gen 22:17) describes Abraham\'s descendants as a blessing to the nations; here it describes the opposing force. The reversal of the blessing-language into opposition anticipates how creation\'s powers are opposed to their Creator until they are reclaimed. Christ comes against "the sand on the seashore" of human opposition — and wins.</p>',
    "5": '<p>A theme: the coalition assembles at Merom to fight Israel — the final pre-battle muster before defeat. In Revelation, the gathering of all nations at Armageddon (Rev 16:16) is the eschatological fulfillment of this pattern: the nations assemble to fight God\'s purposes and are defeated by the coming of the divine warrior (Rev 19:11-21).</p>',
    "6": '<p>A type: "You must hamstring their horses and burn their chariots." The deliberate destruction of military advantage — so that the victory cannot be credited to human technology — is a type of Christ\'s inverted power. "God chose the weak things of the world to shame the strong" (1 Cor 1:27). The cross is the ultimate hamstringing of worldly power: a crucified Messiah defeats death not through force but through weakness (2 Cor 13:4). YHWH\'s instruction to abandon military advantage is a structural anticipation of the "wisdom of the cross."</p>',
    "7": '<p>A revelation of God: the surprise attack — YHWH\'s intervention is unexpected, disruptive, and decisive. "The day of the Lord will come like a thief in the night" (1 Thess 5:2). The divine warrior does not announce himself in advance to the enemy; his coming disrupts and defeats precisely because it is unexpected.</p>',
    "8": '<p>A revelation of God: "The LORD gave them into Israel\'s hand." As with every battle in the campaign, the subject of victory is YHWH, not Israel. "Thanks be to God! He gives us the victory through our Lord Jesus Christ" (1 Cor 15:57). Christ\'s resurrection is YHWH\'s act on behalf of his people — not human achievement but divine gift.</p>',
    "9": '<p>A revelation of God: "Joshua did just as the LORD had told him" — exact obedience, no modification. This is the climactic statement of the whole campaign: YHWH commands, Joshua obeys completely. The Moses → Joshua obedience pattern reaches its NT fulfillment in Christ: "he learned obedience from what he suffered and, once made perfect, became the source of eternal salvation for all who obey him" (Heb 5:8-9).</p>',
    "10": '<p>A revelation of God: Joshua specifically targets Hazor — the dominant city, the head of the coalition, "the leading city among all those kingdoms." Christ targets the head, not just the extremities: he came to destroy "the devil\'s work" (1 John 3:8), to defeat the "strong man" rather than merely plunder his house (Matt 12:29). The decisive strike at the dominant power center is Christ\'s strategy at the cross.</p>',
    "11": '<p>A revelation of God: Hazor — the cultic and political center — is completely destroyed and burned. "The reason the Son of God appeared was to destroy the devil\'s work" (1 John 3:8). The complete destruction of the central stronghold of opposition is what Christ\'s death accomplishes: death itself, sin itself, the accuser himself are definitively defeated, not merely contained.</p>',
    "12": '<p>A direct revelation: "just as Moses the servant of the LORD had commanded." The chain of divine command — from Moses through Joshua — is fulfilled completely. Christ presents himself as the fulfillment of the same chain: "Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them" (Matt 5:17). Every detail of the Mosaic command finds its fulfillment in Christ\'s obedience.</p>',
    "13": '<p>A theme: the cities on their mounds are not burned — they are preserved for settlement and use. Not everything falls under destruction; creation is reclaimed, not annihilated. This reflects the new creation theology of the NT: "creation itself will be liberated from its bondage to decay" (Rom 8:21). Christ\'s salvation is not the abolition of creation but its redemption and restoration.</p>',
    "14": '<p>A revelation of God: the livestock and plunder are kept — material goods are not under the ḥērem. Creation\'s good gifts are not opposed to God; only the spiritual opposition is destroyed. "Everything God created is good, and nothing is to be rejected if it is received with thanksgiving" (1 Tim 4:4). Christ\'s salvation reclaims material creation, not only souls.</p>',
    "15": '<p>A direct revelation: "as the LORD had commanded his servant Moses, so Moses had commanded Joshua, and Joshua carried it out — he left nothing undone of all the LORD had commanded Moses." This three-link chain (YHWH → Moses → Joshua) is the template for the fulfillment chain that reaches its climax in Christ. The one who fulfills all righteousness "left nothing undone" — "it is finished" (John 19:30) is the NT equivalent of this compliance summary. Christ is the Joshua who leaves nothing of the Father\'s commands unfulfilled.</p>',
    "16": '<p>A theme: "Joshua took all this land" — the comprehensive territorial claim. Christ\'s claim is similarly total: "All authority in heaven and on earth has been given to me" (Matt 28:18). The enumeration of every geographical zone — hill country, Negev, Goshen, foothills, Arabah — mirrors the comprehensiveness of "in heaven and on earth."</p>',
    "17": '<p>A theme: the boundary markers — from Mount Halak in the south to Baal-gad in the north — define the full extent of the promised land. Ps 2:8 is the eschatological extension: "Ask me, and I will make the nations your inheritance, the ends of the earth your possession." The land promise under Joshua sets the territorial scope that the psalms expand to cosmic dimensions and that Christ claims as his inheritance.</p>',
    "18": '<p>A theme: "Joshua waged war against all these kings for a long time." The campaign was not instantaneous; it required sustained effort over years. The NT is honest that Christ\'s kingdom advances through sustained historical engagement: "the kingdom of heaven has been subjected to violence, and violent people have been raiding it" (Matt 11:12). The consummation awaits, but the conquest proceeds through time.</p>',
    "19": '<p>A revelation of God: only the Gibeonites made peace — one group, one city-state, found safety through covenant, while all others chose war and perished. "Seek the LORD while he may be found; call on him while he is near" (Isa 55:6). The narrow window of Gibeonite opportunity anticipates the urgency of the gospel offer: the time to seek peace with YHWH is now, before the day of battle arrives.</p>',
    "20": '<p>A revelation of God: "The LORD who hardened their hearts to wage war against Israel." As YHWH hardened Pharaoh\'s heart at the Exodus, so here he hardens the Canaanites\' hearts so that the ḥērem is complete. The NT parallel is John 12:40 (citing Isa 6:10): "He has blinded their eyes and hardened their hearts, so they can neither see with their eyes, nor understand with their hearts, nor turn." The mystery of divine sovereignty in hardening is part of the same plan that leads to salvation for others — Paul\'s treatment in Rom 9-11 applies this exact pattern to Israel\'s present hardening for the sake of Gentile inclusion.</p>',
    "21": '<p>A type: Joshua destroys the Anakim — the giants the previous generation feared and could not face. "We seemed like grasshoppers in our own eyes, and we looked the same to them" (Num 13:33). Christ defeats the powers that dwarf human capacity: "having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross" (Col 2:15). The giants of sin and death, which made Israel appear as grasshoppers, are destroyed by the new Joshua. Hebron — the very location of maximum fear — is the location of maximum victory.</p>',
    "22": '<p>A type (forward): the surviving Anakim in Gaza, Gath, and Ashdod set up the Goliath narrative (1 Sam 17). Goliath of Gath is the last Anakim champion — the giant the second generation will face. David\'s defeat of Goliath is itself a type of Christ\'s defeat of the "strong man" (Matt 12:29): "The LORD who rescued me from the paw of the lion and the paw of the bear will rescue me from the hand of this Philistine" (1 Sam 17:37). The chain runs: YHWH defeats Anakim through Joshua → David defeats Goliath → Christ defeats death, the last enemy (1 Cor 15:26).</p>',
    "23": '<p>A direct forward pointer: "Joshua took the entire land... he gave it as an inheritance to Israel... Then the land had rest from war." Heb 4:8-9 explicitly cites this verse: "For if Joshua had given them rest, God would not have spoken later about another day. There remains, then, a Sabbath-rest for the people of God." The rest Joshua achieves is real but temporary and incomplete — it is the type of the greater rest Christ provides. "Come to me, all you who are weary and burdened, and I will give you rest" (Matt 11:28). Christ is the true Joshua who leads his people into the rest that the land of Canaan could only shadow.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('mkt-christ', 'joshua', existing)
    print('Joshua 9-11 mkt-christ written.')

if __name__ == '__main__':
    main()
